{
   if (msgData.count > 0) {
      OSRTDListNode* pNode = msgData.head;
      ASN1T_RICindication_protocolIEs_element* pElem;
      while (0 != pNode) {
         pElem = (ASN1T_RICindication_protocolIEs_element*) pNode->data;
         if (pElem->id == id) return pElem;
         pNode = pNode->next;
      }
   }
   return 0;
}

int ASN1C_RICindication_protocolIEs::GetAllIEs (ASN1T_ProtocolIE_ID id, 
   ASN1T_RICindication_protocolIEs* pmatches)
{
   if (msgData.count > 0) {
      OSRTDListNode* pNode = msgData.head;
      ASN1T_RICindication_protocolIEs_element* pElem;
      while (0 != pNode) {
         pElem = (ASN1T_RICindication_protocolIEs_element*) pNode->data;
         if (pElem->id == id) {
            if (!rtxDListAppend(getCtxtPtr(), pmatches, pElem))
               return LOG_RTERR(getCtxtPtr(), RTERR_NOMEM);
         }
         pNode = pNode->next;
      }
   }
   return 0;
}

